from flask import Flask, request, redirect, session, url_for
import os
import urllib.parse

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'your-secret-key')

# Configuration
CLIENT_ID = os.environ.get('CLIENT_ID')
CLIENT_SECRET = os.environ.get('CLIENT_SECRET')
AUTHORIZATION_BASE_URL = os.environ.get('AUTHORIZATION_BASE_URL')
TOKEN_URL = os.environ.get('TOKEN_URL')
REDIRECT_URI = os.environ.get('REDIRECT_URI')
DOMAIN = os.environ.get('DOMAIN')

@app.route('/')
def index():
    return '<a href="/login">Login with OAuth</a>'

@app.route('/login')
def login():
    if not REDIRECT_URI:
        return 'REDIRECT_URI not configured', 400
    
    if DOMAIN and DOMAIN not in REDIRECT_URI:
        return 'Invalid redirect_uri: does not match configured domain', 400
    
    authorization_url = f"{AUTHORIZATION_BASE_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={urllib.parse.quote(REDIRECT_URI, safe=':/')}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Authorization failed', 400
    
    # Exchange authorization code for access token
    token_response = requests.post(TOKEN_URL, data={
        'grant_type': 'authorization_code',
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
        'code': code,
        'redirect_uri': REDIRECT_URI
    })
    
    if token_response.status_code != 200:
        return 'Token exchange failed', 400
    
    token_data = token_response.json()
    session['access_token'] = token_data.get('access_token')
    
    return 'Login successful! <a href="/profile">View Profile</a>'

@app.route('/profile')
def profile():
    access_token = session.get('access_token')
    if not access_token:
        return redirect(url_for('login'))
    
    # Use access token to fetch user profile
    profile_response = requests.get(
        'https://api.example.com/user',
        headers={'Authorization': f'Bearer {access_token}'}
    )
    
    if profile_response.status_code == 200:
        return profile_response.json()
    else:
        return 'Failed to fetch profile', 400

if __name__ == '__main__':
    app.run(debug=True)